using CourseCatalog.Models;

namespace CourseCatalog.Services;

public interface ICatalogService
{
    IReadOnlyList<Department> GetDepartments();
    Department? GetDepartment(string departmentId);
    IReadOnlyList<Course> GetCourses(string? departmentId = null, string? searchTerm = null);
    IReadOnlyList<Course> GetFeaturedCourses();
    Course? GetCourse(string courseId);
}

public class CatalogService : ICatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = "cs", Name = "Computer Science", Abbreviation = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = "math", Name = "Mathematics", Abbreviation = "MATH", Description = "Study of numbers, quantity, structure, and space." },
            new() { Id = "eng", Name = "English", Abbreviation = "ENG", Description = "Study of literature, writing, and rhetoric." },
            new() { Id = "phys", Name = "Physics", Abbreviation = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = "hist", Name = "History", Abbreviation = "HIST", Description = "Study of past events and their significance." },
        };

        _courses = new List<Course>
        {
            new()
            {
                Id = "cs101", DepartmentId = "cs", Code = "CS 101", Title = "Introduction to Computer Science",
                Description = "An introductory course covering fundamental concepts of computer science including problem solving, algorithms, data representation, and programming basics using Python.",
                Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Semester = "Fall 2026", Location = "Science Hall 201",
                MaxEnrollment = 120, IsFeatured = true,
                Instructor = new() { Name = "Dr. Ada Lovelace", Title = "Associate Professor", Email = "alovelace@university.edu", Bio = "Dr. Lovelace specializes in algorithms and computational theory with over 15 years of teaching experience. She has published extensively on introductory CS pedagogy.", OfficeLocation = "Tech Building 305" }
            },
            new()
            {
                Id = "cs201", DepartmentId = "cs", Code = "CS 201", Title = "Data Structures and Algorithms",
                Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs, hash tables) and algorithm analysis. Emphasis on design, implementation, and efficiency.",
                Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", Semester = "Fall 2026", Location = "Science Hall 105",
                MaxEnrollment = 80, IsFeatured = false,
                Instructor = new() { Name = "Dr. Alan Turing", Title = "Professor", Email = "aturing@university.edu", Bio = "Dr. Turing is a leading researcher in algorithm design and complexity theory. He has received multiple teaching excellence awards.", OfficeLocation = "Tech Building 410" }
            },
            new()
            {
                Id = "cs301", DepartmentId = "cs", Code = "CS 301", Title = "Database Systems",
                Description = "Introduction to database design and implementation. Covers relational model, SQL, normalization, transaction processing, and modern NoSQL approaches.",
                Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", Semester = "Fall 2026", Location = "Tech Building 102",
                MaxEnrollment = 60, IsFeatured = true,
                Instructor = new() { Name = "Dr. Edgar Codd", Title = "Professor", Email = "ecodd@university.edu", Bio = "Dr. Codd has 20 years of industry and academic experience in database systems. His research focuses on distributed databases and data modeling.", OfficeLocation = "Tech Building 412" }
            },
            new()
            {
                Id = "math101", DepartmentId = "math", Code = "MATH 101", Title = "Calculus I",
                Description = "Limits, continuity, derivatives, and integrals of single-variable functions. Applications to physics, engineering, and the sciences.",
                Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", Semester = "Fall 2026", Location = "Math Building 100",
                MaxEnrollment = 150, IsFeatured = true,
                Instructor = new() { Name = "Dr. Leonhard Euler", Title = "Distinguished Professor", Email = "leuler@university.edu", Bio = "Dr. Euler is an award-winning mathematician whose research spans analysis, number theory, and applied mathematics.", OfficeLocation = "Math Building 215" }
            },
            new()
            {
                Id = "math201", DepartmentId = "math", Code = "MATH 201", Title = "Linear Algebra",
                Description = "Vectors, matrices, linear transformations, eigenvalues, and eigenvectors. Applications in computer science, physics, and engineering.",
                Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", Semester = "Fall 2026", Location = "Math Building 204",
                MaxEnrollment = 90, IsFeatured = false,
                Instructor = new() { Name = "Dr. Emmy Noether", Title = "Professor", Email = "enoether@university.edu", Bio = "Dr. Noether is renowned for her contributions to abstract algebra. She brings theoretical depth and clarity to her undergraduate courses.", OfficeLocation = "Math Building 310" }
            },
            new()
            {
                Id = "eng101", DepartmentId = "eng", Code = "ENG 101", Title = "Composition and Rhetoric",
