@page "/courses"
@using CourseCatalog.Models
@using CourseCatalog.Services
@using CourseCatalog.Components.Shared
@inject ICatalogService Catalog

<PageTitle>Courses – University Course Catalog</PageTitle>

<div class="container py-4">
    <h1 class="mb-4">Course Catalog</h1>

    <form method="get" action="/courses" class="row g-3 mb-4">
        <div class="col-md-6">
            <label for="search" class="form-label">Search</label>
            <input type="text" id="search" name="search" value="@Search"
                   class="form-control" placeholder="Search by title, code, or instructor…" />
        </div>
        <div class="col-md-4">
            <label for="department" class="form-label">Department</label>
            <select id="department" name="department" class="form-select">
                <option value="">All Departments</option>
                @foreach (var dept in _departments)
                {
                    <option value="@dept.Id" selected="@(dept.Id == Department)">@dept.Name</option>
                }
            </select>
        </div>
        <div class="col-md-2 d-flex align-items-end">
            <button type="submit" class="btn btn-primary w-100">Filter</button>
        </div>
    </form>

    @if (_selectedDepartment is not null)
    {
        <div class="alert alert-info py-2">
            Showing courses in <strong>@_selectedDepartment.Name</strong>.
            <a href="/courses?search=@Search" class="ms-2">Clear filter</a>
        </div>
    }

    @if (_courses.Count == 0)
    {
        <div class="alert alert-warning">
            No courses found matching your criteria. Try adjusting your search or filter.
        </div>
    }
    else
    {
        <p class="text-muted">@_courses.Count course(s) found</p>
        <div class="table-responsive">
            <table class="table table-hover align-middle">
                <thead class="table-light">
                    <tr>
                        <th>Code</th>
                        <th>Title</th>
                        <th>Instructor</th>
                        <th class="text-center">Credits</th>
                        <th>Schedule</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var course in _courses)
                    {
                        <CourseListItem Course="course" />
                    }
                </tbody>
            </table>
        </div>
    }
</div>

@code {
    [SupplyParameterFromQuery]
    public string? Search { get; set; }

    [SupplyParameterFromQuery]
    public string? Department { get; set; }

    private IReadOnlyList<Course> _courses = [];
    private IReadOnlyList<Department> _departments = [];
    private Department? _selectedDepartment;

    protected override void OnInitialized()
    {
        _departments = Catalog.GetDepartments();
        _courses = Catalog.GetCourses(Department, Search);
        _selectedDepartment = string.IsNullOrWhiteSpace(Department)
            ? null
            : Catalog.GetDepartment(Department);
    }
}

@page "/enroll"
@using CourseCatalog.Models
@using CourseCatalog.Services
@inject ICatalogService Catalog

<PageTitle>Enrollment Request – University Course Catalog</PageTitle>

<div class="container py-4">
    <h1 class="mb-4">Enrollment Request</h1>

    @if (_submitted)
    {
        <div class="alert alert-success">
            <h4 class="alert-heading">Request Submitted!</h4>
            <p>Thank you, <strong>@_model.FullName</strong>. Your enrollment request for
               <strong>@_selectedCourseTitle</strong> has been received.</p>
            <p>You will receive a confirmation at your university email once processed.</p>
            <hr />
            <a href="/courses" class="btn btn-primary">Browse More Courses</a>
            <a href="/enroll" class="btn btn-outline-secondary ms-2">Submit Another Request</a>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-lg-8">
                <div class="card">
                    <div class="card-body">
                        <form method="post" @formname="enrollment">
                            <AntiforgeryToken />

                            <div class="mb-3">
                                <label for="fullName" class="form-label">Full Name <span class="text-danger">*</span></label>
                                <input type="text" id="fullName" name="_model.FullName" value="@_model.FullName"
                                       class="form-control" required />
                                @if (_errors.ContainsKey(nameof(_model.FullName)))
                                {
                                    <div class="text-danger small mt-1">@_errors[nameof(_model.FullName)]</div>
                                }
                            </div>

                            <div class="mb-3">
                                <label for="studentId" class="form-label">Student ID <span class="text-danger">*</span></label>
                                <input type="text" id="studentId" name="_model.StudentId" value="@_model.StudentId"
                                       class="form-control" placeholder="e.g., STU12345" required />
                                @if (_errors.ContainsKey(nameof(_model.StudentId)))
                                {
                                    <div class="text-danger small mt-1">@_errors[nameof(_model.StudentId)]</div>
                                }
                            </div>

                            <div class="mb-3">
                                <label for="courseId" class="form-label">Course <span class="text-danger">*</span></label>
                                <select id="courseId" name="_model.CourseId" class="form-select" required>
                                    <option value="">— Select a course —</option>
                                    @foreach (var course in _allCourses)
                                    {
                                        <option value="@course.Id" selected="@(course.Id == _model.CourseId)">
                                            @course.Code – @course.Title (@course.Credits cr.)
                                        </option>
                                    }
                                </select>
                                @if (_errors.ContainsKey(nameof(_model.CourseId)))
                                {
                                    <div class="text-danger small mt-1">@_errors[nameof(_model.CourseId)]</div>
                                }
                            </div>

                            <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
                            <a href="/courses" class="btn btn-outline-secondary ms-2">Cancel</a>
                        </form>
                    </div>
                </div>
            </div>

            <div class="col-lg-4">
                <div class="card bg-light">
                    <div class="card-body">
                        <h5 class="card-title">How It Works</h5>
                        <ol class="small">
                            <li>Enter your name and student ID.</li>
                            <li>Select the course you want to enroll in.</li>
                            <li>Submit the form — you'll receive confirmation via email.</li>
                        </ol>
                        <p class="small text-muted mb-0">
                            Need help? Contact the registrar's office at
                            <a href="mailto:registrar@university.edu">registrar@university.edu</a>.
                        </p>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest _model { get; set; } = new();

    [SupplyParameterFromQuery]
    public string? CourseId { get; set; }

    private IReadOnlyList<Course> _allCourses = [];
    private bool _submitted;
    private string _selectedCourseTitle = string.Empty;
    private Dictionary<string, string> _errors = new();

    protected override void OnInitialized()
    {
        _allCourses = Catalog.GetCourses();

        if (!string.IsNullOrWhiteSpace(CourseId) && string.IsNullOrWhiteSpace(_model.CourseId))
            _model.CourseId = CourseId;
    }

    protected override void OnParametersSet()
    {
        if (HttpMethods.IsPost(string.Empty))
            return;

        // Validate on POST
        if (!string.IsNullOrWhiteSpace(_model.FullName) || !string.IsNullOrWhiteSpace(_model.StudentId))
        {
            _errors = Validate(_model);
            if (_errors.Count == 0)
            {
                var course = Catalog.GetCourse(_model.CourseId);
                _selectedCourseTitle = course is not null ? $"{course.Code} – {course.Title}" : _model.CourseId;
                _submitted = true;
            }
        }
    }

    private static Dictionary<string, string> Validate(EnrollmentRequest model)
    {
        var errors = new Dictionary<string, string>();
        var ctx = new System.ComponentModel.DataAnnotations.ValidationContext(model);
        var results = new List<System.ComponentModel.DataAnnotations.ValidationResult>();

        if (!System.ComponentModel.DataAnnotations.Validator.TryValidateObject(model, ctx, results, true))
        {
            foreach (var r in results)
            {
                foreach (var member in r.MemberNames)
                {
                    if (!errors.ContainsKey(member))
                        errors[member] = r.ErrorMessage ?? "Invalid value.";
                }
            }
        }

        return errors;
    }
}

